import sys
from collections import deque

def solve():
    input_data = sys.stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx += 1
    for _ in range(t):
        n, m = int(input_data[idx]), int(input_data[idx+1]); idx += 2
        grid = []
        lab = None
        for i in range(n):
            row = input_data[idx].decode(); idx += 1
            grid.append(list(row))
            for j, c in enumerate(row):
                if c == 'L':
                    lab = (i, j)

        dirs = [(-1,0),(1,0),(0,-1),(0,1)]

        # Count free neighbors for each cell
        free_nbr = [[0]*m for _ in range(n)]
        for i in range(n):
            for j in range(m):
                if grid[i][j] != '#':
                    cnt = 0
                    for di, dj in dirs:
                        ni, nj = i+di, j+dj
                        if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                            cnt += 1
                    free_nbr[i][j] = cnt

        forceable = [[False]*m for _ in range(n)]
        # non_forceable_nbr count = free_nbr initially
        nf_nbr = [row[:] for row in free_nbr]

        queue = deque()
        li, lj = lab
        forceable[li][lj] = True
        queue.append((li, lj))

        while queue:
            i, j = queue.popleft()
            for di, dj in dirs:
                ni, nj = i+di, j+dj
                if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#' and not forceable[ni][nj]:
                    nf_nbr[ni][nj] -= 1
                    if nf_nbr[ni][nj] <= 1:
                        forceable[ni][nj] = True
                        queue.append((ni, nj))

        out = []
        for i in range(n):
            for j in range(m):
                if grid[i][j] == '.' and forceable[i][j]:
                    grid[i][j] = '+'
            out.append(''.join(grid[i]))
        print('\n'.join(out))

